export async function POST(req: NextRequest) {
  try {
    const { messages } = await req.json();
    if (!messages || !Array.isArray(messages)) {
      return NextResponse.json({ error: "Invalid messages" }, { status: 400 });
    }

    // Detect if this is a prompt builder response (needs higher token limit)
    const lastUserMessage = messages[messages.length - 1]?.content?.toLowerCase() ?? "";
    const isPromptBuilderMode =
      lastUserMessage.includes("prompt") ||
      messages.some((m: { role: string; content: string }) =>
        m.role === "assistant" && m.content.includes("---PROMPT START---")
      ) ||
      messages.some((m: { role: string; content: string }) =>
        m.role === "assistant" &&
        (m.content.includes("RISEN") ||
          m.content.includes("CO-STAR") ||
          m.content.includes("which AI tool") ||
          m.content.includes("help me write a prompt"))
      );

    const maxTokens = isPromptBuilderMode ? 1500 : 120;

    const response = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-api-key": process.env.ANTHROPIC_API_KEY || "",
        "anthropic-version": "2023-06-01",
      },
      body: JSON.stringify({
        model: "claude-sonnet-4-20250514",
        max_tokens: maxTokens,
        system: SYSTEM_PROMPT,
        messages: messages.slice(-10),
      }),
    });

    if (!response.ok) {
      const error = await response.text();
      console.error("Anthropic API error:", error);
      return NextResponse.json({ error: "API error" }, { status: 500 });
    }

    const data = await response.json();
    const text = data.content?.[0]?.text ?? "";
    return NextResponse.json({ message: text });
  } catch (err) {
    console.error("Chat route error:", err);
    return NextResponse.json({ error: "Server error" }, { status: 500 });
  }
}
